For Q4, this was my approach in Java using **segment tree** :
- Build a segment tree, intially all filled with ```0```s. (Since constraints are not given, I have assumed N for now as 10^3, however, it can be extended as well).
- Assuming we have list of queries with ```BUILD X``` and ```CHECK X Y``` instructions as list of **strings**. 
- For each ```BUILD X``` , we need to build a house at ```X```. We place a ```1``` at position/index ```X```.
- For each ```CHECK X Y```, we need to find if we can build ```Y``` houses before ```X```. We can find the number of houses already built before ```X``` by querying in the segment tree.
- Subtracting that with ```X```, we will get the number of vacant spots. Then we can compare that value with ```Y```.

```
import java.util.ArrayList;
import java.util.Arrays;

class SegmentTree {
    int[] Seg; // segment tree array
    int[] lazySeg; // lazy propogate array
    int n; // number of elements

    // Initialize and build segment tree with array 'a'
    SegmentTree(int[] a, int n) {
        this.n = n; 
        Seg = new int[4 * n];
        lazySeg = new int[4 * n];
        buildTree(0 , 0 , n - 1 , a);
    }

    // Build segment tree of array 'a'
    private void buildTree(int idx , int start , int end , int[] a) {
        // leaf node 
        if (start == end) {
            this.Seg[idx] = a[start];
            return;
        } 
        int mid = (start + end) / 2;
        buildTree(2 * idx + 1, start, mid, a); 
        buildTree(2 * idx + 2, mid + 1, end, a);    
        this.Seg[idx] = this.Seg[2 * idx + 1] + this.Seg[2 * idx + 2];
    }

    // Update 'targetIdx' in array with 'value'
    public void updateIndex(int idx , int start , int end , int targetIdx , int value) {
        if (start == end) {
            this.Seg[idx] = value;
            return;
        }
        int mid = (start + end) / 2;
        if (targetIdx <= mid) {
            updateIndex(2 * idx + 1, start, mid, targetIdx, value);
        } else {
            updateIndex(2 * idx + 2, mid + 1, end, targetIdx, value);
        }
        this.Seg[idx] = this.Seg[2 * idx + 1] + this.Seg[2 * idx + 2];
    }

    // Query in range [l:r]
    public int query(int idx , int start , int end , int l , int r) {
        if (l > r || r < start || l > end) {
            return 0; // No overlap
        }

        if (l <= start && end <= r) {
            return this.Seg[idx]; // Complete overlap
        }

        int mid = (start + end) / 2;
        int leftQuery = query(2 * idx + 1, start, mid, l, r);
        int rightQuery = query(2 * idx + 2, mid + 1, end, l, r);
        return leftQuery + rightQuery;
    }
}


// Solution class
public class Solution {
    public static void main(String[] args) {
        int n = 10000;
        int[] a = new int[n];
        SegmentTree segmentTreeObject = new SegmentTree(a, n); // build segment tree, initialize with 0s

        // queries list
        ArrayList<String> queries = new ArrayList<>(Arrays.asList(
            "BUILD 2",
            "CHECK 3 2",
            "BUILD 5",
            "CHECK 9 1",
            "CHECK 3 3"
        ));

        // iterate through queries
        for (String query : queries) {

        System.out.println(query);

        // if query is BUILD X
        // place 1 at 'X' indication house built on 'X'

            if (query.startsWith("BUILD")) {
                int placeHouse = Integer.parseInt(query.split(" ")[1]);
                segmentTreeObject.updateIndex(0, 0, n - 1, placeHouse, 1); // Update the segment tree
                System.out.println("HOUSE BUILT ON " + placeHouse);
            } else if (query.startsWith("CHECK")) {

        // if query is CHECK X Y
        // find number of houses built before 'X'
                String[] parts = query.split(" ");
                int toCheckBefore = Integer.parseInt(parts[1]); // X
                int targetHousesToBuild = Integer.parseInt(parts[2]); // Y

                int numberOfBuildHouses = segmentTreeObject.query(0, 0, n - 1, 0, toCheckBefore - 1);

        // if there are enough spots to build 'targetHousesToBuild' then print YES
        // else print NO
                if(toCheckBefore - numberOfBuildHouses >= targetHousesToBuild) {
                    System.out.println("YES");
                }
                else {
                    System.out.println("NO");
                }

            }
        }
    }
}
