```
# include <bits/stdc++.h>
using namespace std;

// comparator 
// return smaller difference string OR
// return lexicogrpahhically small if difference is same
bool compare(pair<string,int>a , pair<string,int>b ) {
    if(a.second == b.second) return a.first < b.first;
    return a.second < b.second;
}


// return true if c is vowel 
bool isVowel(char c) {
    return (
        c == 'A' || c == 'a' ||
        c == 'E' || c == 'e' ||
        c == 'I' || c == 'i' ||
        c == 'O' || c == 'o' ||
        c == 'U' || c == 'u'
    );
}

// solve 
vector<string> solve(string sentence) {
    int length = sentence.length();
    vector<string>result;

    string word = "";
    int vowelCount = 0;
    int consonantCount = 0;
    vector<pair<string,int>> wordsList;

    // iterate through string
    for(char ch : sentence) {

        // if 'ch' is a character 
        if(ch != ' ') {
            word += ch; // keep forming current word

            // count vowel and consonants
            if(isVowel(ch) == true) vowelCount += 1;
            else consonantCount += 1;
        }
        else {
           //word has ended 
           int diff = abs(vowelCount - consonantCount); // difference
           wordsList.push_back({word , diff}); // push {word , difference}

           // reset for next word 
           vowelCount = 0;
           consonantCount = 0;
           word = "";
        }
    }
    wordsList.push_back({word , abs(vowelCount - consonantCount)});//push last word

    sort(begin(wordsList) , end(wordsList) , compare); // sort list using comparator

    // push strings into result 
    for(auto i : wordsList) {
        result.push_back(i.first);
    }
    return result;
}

int main()
{
    string sentence = "this is a sentence";
    vector<string>ans = solve(sentence);
    for(string i : ans) cout << i << "\n"; 
    return 0;
} 
